def merge_intervals(intervals: list[tuple[int, int]]) -> list[tuple[int, int]]:
    if not intervals:
        return []

    # Sort intervals based on the start value
    intervals.sort(key=lambda x: x[0])

    merged = [intervals[0]]
    for current_start, current_end in intervals[1:]:
        last_end = merged[-1][1]

        if current_start <= last_end:
            # Merge overlapping intervals
            merged[-1] = (merged[-1][0], max(last_end, current_end))
        else:
            # No overlap, add new interval
            merged.append((current_start, current_end))

    return merged

def merge_intervals(intervals):
    if not intervals:
        return []

    # Sort the intervals based on their starting values
    intervals.sort(key=lambda x: x[0])

    merged = [intervals[0]]
    for current_start, current_end in intervals[1:]:
        last_merged_start, last_merged_end = merged[-1]

        if current_start <= last_merged_end:
            # If the current interval overlaps with the last one in 'merged', merge them
            merged[-1] = (last_merged_start, max(last_merged_end, current_end))
        else:
            # Otherwise, add this interval to our list of merged intervals as is.
            merged.append((current_start, current_end))

    return merged
